import json,sys,urllib.request,urllib.error,time,copy
K=sys.argv[1]; B='https://irynakarmazina.app.n8n.cloud/api/v1/'
def call(method,u,data=None,budget=40):
    h={'X-N8N-API-KEY':K}
    if data is not None: h['Content-Type']='application/json'
    t=time.monotonic(); last=None
    while time.monotonic()-t<budget:
        try:
            r=urllib.request.urlopen(urllib.request.Request(B+u,data=data,method=method,headers=h),timeout=15)
            return r.status, r.read()
        except urllib.error.HTTPError as e:
            if e.code in (404,502,503): last=e; time.sleep(3); continue
            return e.code, e.read()
        except Exception as e:
            last=e; time.sleep(3)
    return None, str(last).encode()
mk=json.load(open('/root/mk-backup-JQKA35haUsXU4XqE.json'))
readn=writen=None
for n in mk['nodes']:
    if n.get('name')=='Читаємо CRM': readn=n
    if n.get('name')=='Запис у CRM': writen=n
rn=copy.deepcopy(readn); rn['name']='Read'; rn['id']='r1'; rn['position']=[220,0]
wn=copy.deepcopy(writen); wn['name']='Write'; wn['id']='w1'; wn['position']=[680,0]
wn['parameters']['columns']={'mappingMode':'autoMapInputData','matchingColumns':['Угода'],'schema':[]}
trig={'parameters':{'httpMethod':'POST','path':'claude-bulk-deliv','responseMode':'responseNode','options':{}},'name':'Trigger','type':'n8n-nodes-base.webhook','typeVersion':2,'position':[0,0],'id':'t1','webhookId':'claude-bulk-deliv'}
filt={'parameters':{'jsCode':"const out=[];for(const it of $input.all()){const r=it.json;if(String(r['Статус']||'').trim()==='Завантажений на авто/потяг' && String(r['Угода']||'').trim()){out.push({json:{'Угода':r['Угода'],'Статус':'Вантаж доставлено','_bl':r['BL/Booking']||'','_eta':r['ETA порт (план)']||r['ETA порт (факт)']||'','_kl':r['Клієнт']||''}});}}return out;"},'name':'Filter','type':'n8n-nodes-base.code','typeVersion':2,'position':[440,0],'id':'f1'}
# Write only Угода+Статус: strip preview fields before write via a splitter code
strip={'parameters':{'jsCode':"return $input.all().map(x=>({json:{'Угода':x.json['Угода'],'Статус':x.json['Статус']}}));"},'name':'Strip','type':'n8n-nodes-base.code','typeVersion':2,'position':[560,0],'id':'s1'}
summ={'parameters':{'jsCode':"const f=$('Filter').all().map(x=>x.json);return [{json:{count:f.length,deals:f.map(d=>({Угода:d['Угода'],bl:d['_bl'],eta:d['_eta'],kl:d['_kl']}))}}];"},'name':'Summary','type':'n8n-nodes-base.code','typeVersion':2,'position':[900,0],'id':'su1'}
resp={'parameters':{'respondWith':'json','responseBody':'={{ JSON.stringify($json) }}','options':{}},'name':'Respond','type':'n8n-nodes-base.respondToWebhook','typeVersion':1,'position':[1120,0],'id':'rp1'}
wf={'name':'ONESHOT bulk-delivered (Claude)','nodes':[trig,rn,filt,strip,wn,summ,resp],'connections':{'Trigger':{'main':[[{'node':'Read','type':'main','index':0}]]},'Read':{'main':[[{'node':'Filter','type':'main','index':0}]]},'Filter':{'main':[[{'node':'Strip','type':'main','index':0}]]},'Strip':{'main':[[{'node':'Write','type':'main','index':0}]]},'Write':{'main':[[{'node':'Summary','type':'main','index':0}]]},'Summary':{'main':[[{'node':'Respond','type':'main','index':0}]]}},'settings':{'executionOrder':'v1'}}
st,body=call('POST','workflows',json.dumps(wf).encode())
if st not in (200,201): print('CREATE fail',st,body[:300]); sys.exit()
wid=json.loads(body).get('id'); print('created',wid)
call('POST','workflows/'+wid+'/activate')
time.sleep(4)
