    r=U.urlopen(U.Request('https://irynakarmazina.app.n8n.cloud/webhook/claude-bulk-deliv',data=b'{}',method='POST',headers={'Content-Type':'application/json'}),timeout=90)
    out=r.read().decode('utf-8','ignore')
    print('RESULT:',out[:1500])
except Exception as e:
    print('webhook err',e)
